   242→## Module: Products
   243→
   244→### GET /api/products
   245→List products from a specific shop with pagination and search.
   246→
   247→**Query Params:**
   248→```typescript
   249→shopId: string;         // required — internal shop ID
   250→page?: number;          // default 1
   251→limit?: number;         // default 20, max 100
   252→search?: string;        // search by name or SKU
   253→status?: "ACTIVE" | "INACTIVE" | "SOLD_OUT" | "ALL";   // default "ALL"
   254→```
   255→
   256→**Response 200:**
   257→```typescript
   258→{
   259→  success: true;
   260→  data: {
   261→    products: Array<{
   262→      id: string;               // internal ID
   263→      platformProductId: string; // Shopee item_id or TikTok product_id
   264→      name: string;
   265→      coverImage: string;       // URL
   266→      status: "ACTIVE" | "INACTIVE" | "SOLD_OUT";
   267→      totalStock: number;       // sum of all variant stocks
   268→      priceRange: {
   269→        min: number;
   270→        max: number;
   271→        currency: string;       // "IDR", "MYR", etc
   272→      };
   273→      variantCount: number;
   274→      updatedAt: string;
   275→    }>;
   276→  };
   277→  meta: {
   278→    page: number;
   279→    limit: number;
   280→    total: number;
   281→    hasMore: boolean;
   282→  }
   283→}
   284→```
