     1→import Fastify from 'fastify';
     2→import cors from '@fastify/cors';
     3→import helmet from '@fastify/helmet';
     4→import jwt from '@fastify/jwt';
     5→import rateLimit from '@fastify/rate-limit';
     6→import { env } from './utils/env';
     7→import { logger } from './utils/logger';
     8→import { registerRoutes } from './modules';
     9→import { prisma } from './database/client';
    10→import { redis } from './cache/redis';
    11→
    12→const app = Fastify({ logger: false });
    13→
    14→async function bootstrap() {
    15→  // Plugins
    16→  await app.register(helmet);
    17→  await app.register(cors, { origin: env.CORS_ORIGIN });
    18→  await app.register(jwt, { secret: env.JWT_SECRET });
    19→  await app.register(rateLimit, { max: 100, timeWindow: '1 minute' });
    20→
    21→  // Routes
    22→  await registerRoutes(app);
    23→
    24→  // Health check
    25→  app.get('/health', async () => ({
    26→    status: 'ok',
    27→    timestamp: new Date().toISOString(),
    28→    services: {
    29→      database: 'connected',
    30→      redis: 'connected',
    31→    },
    32→  }));
    33→
    34→  // Start
    35→  await app.listen({ port: env.PORT, host: '0.0.0.0' });
    36→  logger.info(`Server running on port ${env.PORT}`);
    37→}
    38→
