     1→import crypto from 'crypto';
     2→
     3→const ALGORITHM = 'aes-256-gcm';
     4→const IV_LENGTH = 12;
     5→
     6→function getKey(): Buffer {
     7→  return Buffer.from(process.env.ENCRYPTION_KEY ?? '', 'hex');
     8→}
     9→
    10→export function encrypt(text: string): string {
    11→  const iv = crypto.randomBytes(IV_LENGTH);
    12→  const cipher = crypto.createCipheriv(ALGORITHM, getKey(), iv);
    13→  const encrypted = Buffer.concat([cipher.update(text, 'utf8'), cipher.final()]);
    14→  const tag = (cipher as any).getAuthTag();
    15→  return `${iv.toString('hex')}:${tag.toString('hex')}:${encrypted.toString('hex')}`;
    16→}
    17→
    18→export function decrypt(encryptedText: string): string {
    19→  const [ivHex, tagHex, dataHex] = encryptedText.split(':');
    20→  const iv = Buffer.from(ivHex, 'hex');
    21→  const tag = Buffer.from(tagHex, 'hex');
    22→  const data = Buffer.from(dataHex, 'hex');
    23→  const decipher = crypto.createDecipheriv(ALGORITHM, getKey(), iv);
    24→  (decipher as any).setAuthTag(tag);
    25→  return decipher.update(data).toString() + decipher.final('utf8');
    26→}
