     1→import bcrypt from 'bcryptjs';
     2→import crypto from 'crypto';
     3→import { prisma } from '../../database/client';
     4→import type { RegisterInput, LoginInput } from './auth.schema';
     5→
     6→export class AuthService {
     7→  async register(input: RegisterInput) {
     8→    const existing = await prisma.user.findUnique({ where: { email: input.email } });
     9→    if (existing) throw new Error('EMAIL_TAKEN');
    10→
    11→    const passwordHash = await bcrypt.hash(input.password, 12);
    12→    const user = await prisma.user.create({
    13→      data: { email: input.email, name: input.name, passwordHash },
    14→      select: { id: true, email: true, name: true },
    15→    });
    16→    return user;
    17→  }
    18→
    19→  async login(input: LoginInput) {
    20→    const user = await prisma.user.findUnique({ where: { email: input.email } });
    21→    if (!user) throw new Error('INVALID_CREDENTIALS');
    22→
    23→    const valid = await bcrypt.compare(input.password, user.passwordHash);
    24→    if (!valid) throw new Error('INVALID_CREDENTIALS');
    25→
    26→    return { id: user.id, email: user.email, name: user.name };
    27→  }
    28→
    29→  async createRefreshToken(userId: string): Promise<string> {
    30→    const token = crypto.randomBytes(40).toString('hex');
    31→    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000); // 30 days
    32→    await prisma.refreshToken.create({ data: { token, userId, expiresAt } });
    33→    return token;
    34→  }
    35→
    36→  async verifyRefreshToken(token: string) {
    37→    const record = await prisma.refreshToken.findUnique({ where: { token } });
    38→    if (!record || record.revokedAt || record.expiresAt < new Date()) {
    39→      throw new Error('INVALID_REFRESH_TOKEN');
    40→    }
    41→    return record;
    42→  }
    43→
    44→  async revokeRefreshToken(token: string) {
    45→    await prisma.refreshToken.update({
    46→      where: { token },
    47→      data: { revokedAt: new Date() },
    48→    });
    49→  }
    50→}
    51→
    52→export const authService = new AuthService();
