     1→import { Worker } from 'bullmq';
     2→import { redis } from '../cache/redis';
     3→import { prisma } from '../database/client';
     4→import { inventoryService } from '../modules/inventory/inventory.service';
     5→import { priceService } from '../modules/price/price.service';
     6→import { logger } from '../utils/logger';
     7→
     8→const BATCH_SIZE = 50;
     9→const BATCH_DELAY_MS = 200;
    10→
    11→export const bulkWorker = new Worker('bulk-update', async (job) => {
    12→  const { jobId, userId, shopId, items } = job.data;
    13→
    14→  await prisma.bulkJob.update({ where: { id: jobId }, data: { status: 'PROCESSING', startedAt: new Date() } });
    15→
    16→  const errors: any[] = [];
    17→  let successCount = 0;
    18→
    19→  for (let i = 0; i < items.length; i += BATCH_SIZE) {
    20→    const batch = items.slice(i, i + BATCH_SIZE);
    21→
    22→    for (const item of batch) {
    23→      try {
    24→        if (job.name === 'process-stock') {
    25→          await inventoryService.updateStock(userId, item.productId, { shopId, updates: [{ variantId: item.variantId, stock: item.stock }] });
    26→        } else {
    27→          await priceService.updatePrice(userId, item.productId, { shopId, updates: [{ variantId: item.variantId, price: item.price, originalPrice: item.originalPrice }] });
    28→        }
    29→        successCount++;
    30→      } catch (err: any) {
    31→        errors.push({ productId: item.productId, variantId: item.variantId, errorCode: 'PLATFORM_ERROR', message: err.message });
    32→      }
    33→    }
    34→
    35→    const progress = Math.round(((i + batch.length) / items.length) * 100);
    36→    await prisma.bulkJob.update({ where: { id: jobId }, data: { progress, successCount, failedCount: errors.length } });
    37→    await job.updateProgress(progress);
    38→
    39→    if (i + BATCH_SIZE < items.length) await new Promise(r => setTimeout(r, BATCH_DELAY_MS));
    40→  }
    41→
    42→  const finalStatus = errors.length === 0 ? 'COMPLETED' : successCount > 0 ? 'PARTIAL' : 'FAILED';
    43→  await prisma.bulkJob.update({
    44→    where: { id: jobId },
    45→    data: { status: finalStatus, progress: 100, successCount, failedCount: errors.length, errors, completedAt: new Date() },
    46→  });
    47→
    48→  logger.info({ jobId, status: finalStatus, successCount, failed: errors.length }, 'Bulk job completed');
    49→}, { connection: redis as any, concurrency: 3 });
