import type { ShopConnection } from '@prisma/client';

export const shopeeProduct = {
  async getItemList(shop: ShopConnection, page: number, limit: number, search?: string): Promise<{
    items: Array<{ item_id: number; item_status: string }>;
    total_count: number;
    has_next_page: boolean;
    next_offset: number;
  }> {
    const client = createShopeeClient(shop);
    const offset = (page - 1) * limit;

    const res = await client.get('/api/v2/product/get_item_list', {
      params: {
        offset,
        page_size: limit,
        item_status: 'NORMAL',
      },
    });

    const raw = res.data.response ?? {};
    return {
      items: raw.item ?? [],
      total_count: raw.total_count ?? 0,
      has_next_page: raw.has_next_page ?? false,
      next_offset: raw.next_offset ?? 0,
    };
  },

  async getItemBaseInfo(shop: ShopConnection, itemIds: number[]): Promise<unknown[]> {
    const client = createShopeeClient(shop);
    const res = await client.get('/api/v2/product/get_item_base_info', {
      params: { item_id_list: itemIds.join(','), need_tax_info: false, need_complaint_policy: false },
    });
    return res.data.response?.item_list ?? [];
  },

  async updateStock(
    shop: ShopConnection,
    itemId: string,
    updates: Array<{ variantId: string; stock: number }>,
  ): Promise<{ updated: typeof updates; platform: string; updatedAt: string }> {
    const client = createShopeeClient(shop);

    const stockList = updates.map((u) => ({
      model_id: Number(u.variantId),
      seller_stock: [{ stock: u.stock }],
    }));

    const res = await client.post('/api/v2/product/update_stock', {
      item_id: Number(itemId),
      stock_list: stockList,
    });

    for (const u of updates) {
      await prisma.updateLog.create({
        data: {
          shopConnectionId: shop.id,
          platformProductId: itemId,
          variantId: u.variantId,
          updateType: 'STOCK',
          status: res.data.error ? 'FAILED' : 'SUCCESS',
          newValue: { stock: u.stock },
          platformResponse: res.data,
        },
      });
    }

    return { updated: updates, platform: 'SHOPEE', updatedAt: new Date().toISOString() };
  },

  async updatePrice(
    shop: ShopConnection,
    itemId: string,
    updates: Array<{ variantId: string; price: number; originalPrice?: number }>,
  ): Promise<{ updated: typeof updates; updatedAt: string }> {
    const client = createShopeeClient(shop);

    const priceList = updates.map((u) => ({
      model_id: Number(u.variantId),
      original_price: u.originalPrice ?? u.price,
      current_price: u.price,
    }));

    const res = await client.post('/api/v2/product/update_price_info', {
      item_id: Number(itemId),
      price_list: priceList,
    });

    for (const u of updates) {
      await prisma.updateLog.create({
        data: {
          shopConnectionId: shop.id,
          platformProductId: itemId,
          variantId: u.variantId,
          updateType: 'PRICE',
          status: res.data.error ? 'FAILED' : 'SUCCESS',
          newValue: { price: u.price, originalPrice: u.originalPrice },
          platformResponse: res.data,
        },
      });
    }

    return { updated: updates, updatedAt: new Date().toISOString() };
  },

  async uploadImage(shop: ShopConnection, imageBuffer: Buffer, mimeType: string): Promise<{ imageId: string; imageUrl: string; width: number; height: number }> {
    const client = createShopeeClient(shop);
    const FormData = (await import('form-data')).default;
    const form = new FormData();
    form.append('image', imageBuffer, { filename: 'upload.jpg', contentType: mimeType });

    const res = await client.post('/api/v2/media_space/upload_image', form, {
      headers: form.getHeaders(),
    });

    const img = res.data.response?.image_info;
    return {
      imageId: img?.image_id ?? '',
      imageUrl: img?.image_url ?? '',
      width: img?.image_width ?? 0,
      height: img?.image_height ?? 0,
    };
  },
};

import { createTikTokClient } from './tiktok.client';
import { prisma } from '../../database/client';
import type { ShopConnection } from '@prisma/client';

export const tiktokProduct = {
  async getProductList(shop: ShopConnection, page: number, limit: number, search?: string): Promise<{
    products: Array<{ id: string; status: string }>;
    total_count: number;
    has_more: boolean;
    next_page_token: string;
  }> {
    const client = createTikTokClient(shop);
    const body: Record<string, unknown> = {
      page_size: limit,
      sort_field: 'CREATE_TIME',
      sort_order: 'DESC',
    };
    if (search) body.keyword = search;

    const res = await client.post('/product/202309/products/search', body, {
      params: { page_size: limit },
    });

    const d = res.data.data ?? {};
    return {
      products: d.products ?? [],
      total_count: d.total_count ?? 0,
      has_more: d.next_page_token != null && d.next_page_token !== '',
      next_page_token: d.next_page_token ?? '',
    };
  },

  async getProductDetail(shop: ShopConnection, productId: string): Promise<unknown> {
    const client = createTikTokClient(shop);
    const res = await client.get(`/product/202309/products/${productId}`);
    return res.data.data ?? null;
  },

  async updateInventory(
    shop: ShopConnection,
    productId: string,
    updates: Array<{ variantId: string; stock: number }>,
  ): Promise<{ updated: typeof updates; platform: string; updatedAt: string }> {
    const client = createTikTokClient(shop);

    const res = await client.put('/product/202309/inventories', {
      skus: updates.map((u) => ({
        id: u.variantId,
        inventory: [{ warehouse_id: 'default', quantity: u.stock }],
      })),
    });

    for (const u of updates) {
      await prisma.updateLog.create({
        data: {
          shopConnectionId: shop.id,
          platformProductId: productId,
          variantId: u.variantId,
          updateType: 'STOCK',
          status: res.data.code === 0 ? 'SUCCESS' : 'FAILED',
          newValue: { stock: u.stock },
          platformResponse: res.data,
        },
      });
    }

    return { updated: updates, platform: 'TIKTOK', updatedAt: new Date().toISOString() };
  },

  async updatePrice(
    shop: ShopConnection,
    productId: string,
    updates: Array<{ variantId: string; price: number; originalPrice?: number }>,
  ): Promise<{ updated: typeof updates; updatedAt: string }> {
    const client = createTikTokClient(shop);

    const res = await client.put(`/product/202309/products/${productId}/prices`, {
      skus: updates.map((u) => ({
        id: u.variantId,
        price: { amount: String(u.price), currency: 'IDR' },
      })),
    });

    for (const u of updates) {
      await prisma.updateLog.create({
        data: {
          shopConnectionId: shop.id,
          platformProductId: productId,
          variantId: u.variantId,
          updateType: 'PRICE',
          status: res.data.code === 0 ? 'SUCCESS' : 'FAILED',
          newValue: { price: u.price, originalPrice: u.originalPrice },
          platformResponse: res.data,
        },
      });
    }

    return { updated: updates, updatedAt: new Date().toISOString() };
  },

  async uploadImage(shop: ShopConnection, imageBuffer: Buffer, mimeType: string): Promise<{ imageId: string; imageUrl: string; width: number; height: number }> {
    const client = createTikTokClient(shop);
    const FormData = (await import('form-data')).default;
    const form = new FormData();
    form.append('data', imageBuffer, { filename: 'upload.jpg', contentType: mimeType });
    form.append('use_case', 'MAIN_IMAGE');

    const res = await client.post('/product/202309/images/upload', form, {
      headers: form.getHeaders(),
    });

    const img = res.data.data;
    return {
      imageId: img?.uri ?? '',
      imageUrl: img?.url ?? '',
      width: img?.width ?? 0,
      height: img?.height ?? 0,
    };
  },
};

import crypto from 'crypto';
import axios from 'axios';
import { prisma } from '../../database/client';
import { encrypt } from '../../utils/crypto';
import { createShopeeSign } from './shopee.client';

const PARTNER_ID = process.env.SHOPEE_PARTNER_ID!;
const REDIRECT_URI = `${process.env.API_BASE_URL}/api/shops/shopee/callback`;

export const shopeeAuth = {
  async generateAuthUrl(userId: string): Promise<{ url: string; state: string }> {
    const state = crypto.randomBytes(16).toString('hex');
    const timestamp = Math.floor(Date.now() / 1000);
    const path = '/api/v2/shop/auth_partner';
    const sign = createShopeeSign(path, timestamp);

    await prisma.oAuthState.create({
      data: {
        state,
        userId,
        platform: 'SHOPEE',
        expiresAt: new Date(Date.now() + 10 * 60 * 1000),
      },
    });

    const url = `https://partner.shopeemobile.com${path}?partner_id=${PARTNER_ID}&timestamp=${timestamp}&sign=${sign}&redirect=${encodeURIComponent(REDIRECT_URI)}&state=${state}`;
    return { url, state };
  },

  async exchangeCode(
    code: string,
    shopId: string,
  ): Promise<{ accessToken: string; refreshToken: string; expiresAt: Date }> {
    const timestamp = Math.floor(Date.now() / 1000);
    const path = '/api/v2/auth/token/get';
    const sign = createShopeeSign(path, timestamp);

    const res = await axios.post(
      `https://partner.shopeemobile.com${path}`,
      { code, shop_id: Number(shopId), partner_id: Number(PARTNER_ID) },
      { params: { partner_id: Number(PARTNER_ID), timestamp, sign } },
    );

    return {
      accessToken: res.data.access_token,
      refreshToken: res.data.refresh_token,
      expiresAt: new Date(Date.now() + res.data.expire_in * 1000),
    };
  },

  async refreshAccessToken(
    shop: import('@prisma/client').ShopConnection,
  ): Promise<{ accessToken: string; refreshToken: string; expiresAt: Date }> {
    const { decrypt } = await import('../../utils/crypto');
    const oldRefreshToken = decrypt(shop.refreshTokenEnc);

    const timestamp = Math.floor(Date.now() / 1000);
    const path = '/api/v2/auth/access_token/get';
    const sign = createShopeeSign(path, timestamp);

    const res = await axios.post(
      `https://partner.shopeemobile.com${path}`,
      {
        refresh_token: oldRefreshToken,
        shop_id: Number(shop.platformShopId),
        partner_id: Number(PARTNER_ID),
      },
      { params: { partner_id: Number(PARTNER_ID), timestamp, sign } },
    );

    return {
      accessToken: res.data.access_token,
      refreshToken: res.data.refresh_token,
      expiresAt: new Date(Date.now() + res.data.expire_in * 1000),
    };
  },

  async getShopInfo(accessToken: string, shopId: string): Promise<{ shopName: string; region: string }> {
    const timestamp = Math.floor(Date.now() / 1000);
    const path = '/api/v2/shop/get_shop_info';
    const sign = createShopeeSign(path, timestamp, accessToken, shopId);

    const res = await axios.get(`https://partner.shopeemobile.com${path}`, {
      params: {
        partner_id: Number(PARTNER_ID),
        timestamp,
        access_token: accessToken,
        shop_id: Number(shopId),
        sign,
      },
    });

    return {
      shopName: res.data.response?.shop_name ?? `Shop ${shopId}`,
      region: res.data.response?.region ?? 'ID',
    };
  },

  async handleCallback(
    userId: string,
    code: string,
    shopId: string,
    state: string,
  ): Promise<import('@prisma/client').ShopConnection> {
    const oauthState = await prisma.oAuthState.findUnique({ where: { state } });
    if (!oauthState || oauthState.userId !== userId || oauthState.expiresAt < new Date() || oauthState.usedAt) {
      throw new Error('INVALID_STATE');
    }

    await prisma.oAuthState.update({ where: { id: oauthState.id }, data: { usedAt: new Date() } });

    const { accessToken, refreshToken, expiresAt } = await shopeeAuth.exchangeCode(code, shopId);
    const shopInfo = await shopeeAuth.getShopInfo(accessToken, shopId);

    const shop = await prisma.shopConnection.upsert({
      where: {
        userId_platform_platformShopId: { userId, platform: 'SHOPEE', platformShopId: shopId },
      },
      create: {
        userId,
        platform: 'SHOPEE',
        platformShopId: shopId,
        shopName: shopInfo.shopName,
        region: shopInfo.region,
        status: 'ACTIVE',
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
      },
      update: {
        shopName: shopInfo.shopName,
        region: shopInfo.region,
        status: 'ACTIVE',
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
        disconnectedAt: null,
      },
    });

    return shop;
  },
};

import crypto from 'crypto';
import axios from 'axios';
import { prisma } from '../../database/client';
import { encrypt } from '../../utils/crypto';

const APP_KEY = process.env.TIKTOK_APP_KEY!;
const APP_SECRET = process.env.TIKTOK_APP_SECRET!;
const REDIRECT_URI = `${process.env.API_BASE_URL}/api/shops/tiktok/callback`;

export const tiktokAuth = {
  async generateAuthUrl(userId: string): Promise<{ url: string; state: string }> {
    const state = crypto.randomBytes(16).toString('hex');

    await prisma.oAuthState.create({
      data: {
        state,
        userId,
        platform: 'TIKTOK',
        expiresAt: new Date(Date.now() + 10 * 60 * 1000),
      },
    });

    const url = `https://services.tiktokshop.com/open/authorize?service_id=${APP_KEY}&state=${state}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}`;
    return { url, state };
  },

  async exchangeCode(code: string): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresAt: Date;
    openId: string;
  }> {
    const res = await axios.post(
      'https://open-api.tiktokglobalshop.com/api/v2/token/oauth/access_token',
      { app_key: APP_KEY, app_secret: APP_SECRET, code, grant_type: 'authorized_code' },
    );

    const d = res.data.data;
    return {
      accessToken: d.access_token,
      refreshToken: d.refresh_token,
      expiresAt: new Date(Date.now() + d.access_token_expire_in * 1000),
      openId: d.open_id,
    };
  },

  async refreshAccessToken(shop: import('@prisma/client').ShopConnection): Promise<{
    accessToken: string;
    refreshToken: string;
    expiresAt: Date;
  }> {
    const { decrypt } = await import('../../utils/crypto');
    const oldRefreshToken = decrypt(shop.refreshTokenEnc);

    const res = await axios.post(
      'https://open-api.tiktokglobalshop.com/api/v2/token/refresh_token',
      { app_key: APP_KEY, app_secret: APP_SECRET, refresh_token: oldRefreshToken, grant_type: 'refresh_token' },
    );

    const d = res.data.data;
    return {
      accessToken: d.access_token,
      refreshToken: d.refresh_token,
      expiresAt: new Date(Date.now() + d.access_token_expire_in * 1000),
    };
  },

  async getShopList(accessToken: string): Promise<Array<{ shop_id: string; shop_name: string; region: string }>> {
    const res = await axios.get('https://open-api.tiktokglobalshop.com/seller/202309/shops', {
      headers: { 'x-tts-access-token': accessToken },
    });
    return res.data.data?.shops ?? [];
  },

  async handleCallback(
    userId: string,
    code: string,
    state: string,
  ): Promise<import('@prisma/client').ShopConnection> {
    const oauthState = await prisma.oAuthState.findUnique({ where: { state } });
    if (!oauthState || oauthState.userId !== userId || oauthState.expiresAt < new Date() || oauthState.usedAt) {
      throw new Error('INVALID_STATE');
    }

    await prisma.oAuthState.update({ where: { id: oauthState.id }, data: { usedAt: new Date() } });

    const { accessToken, refreshToken, expiresAt } = await tiktokAuth.exchangeCode(code);
    const shops = await tiktokAuth.getShopList(accessToken);
    const shopInfo = shops[0] ?? { shop_id: 'unknown', shop_name: 'TikTok Shop', region: 'ID' };

    const shop = await prisma.shopConnection.upsert({
      where: {
        userId_platform_platformShopId: {
          userId,
          platform: 'TIKTOK',
          platformShopId: shopInfo.shop_id,
        },
      },
      create: {
        userId,
        platform: 'TIKTOK',
        platformShopId: shopInfo.shop_id,
        shopName: shopInfo.shop_name,
        region: shopInfo.region,
        status: 'ACTIVE',
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
      },
      update: {
        shopName: shopInfo.shop_name,
        region: shopInfo.region,
        status: 'ACTIVE',
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
        disconnectedAt: null,
      },
    });

    return shop;
  },
};

import type { FastifyInstance } from 'fastify';
import { shopService } from './shop.service';

export async function shopRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/shops', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const shops = await shopService.listShops(req.user.sub);
    return reply.send({ success: true, data: { shops } });
  });

  app.get('/api/shops/shopee/auth-url', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const result = await shopService.getShopeeAuthUrl(req.user.sub);
    return reply.send({ success: true, data: result });
  });

  app.get('/api/shops/shopee/callback', async (req: any, reply) => {
    const { code, shop_id, state } = req.query;
    if (!code || !shop_id || !state) {
      return reply.status(400).send({ success: false, error: { code: 'MISSING_PARAMS', message: 'Missing OAuth params' } });
    }
    const shop = await shopService.handleShopeeCallback(req.user?.sub ?? '', code, shop_id, state);
    return reply.send({
      success: true,
      data: {
        shop: {
          id: shop.id,
          platformShopId: shop.platformShopId,
          shopName: shop.shopName,
          platform: shop.platform,
          region: shop.region,
          connectedAt: shop.createdAt.toISOString(),
        },
      },
    });
  });

  app.post('/api/shops/shopee/refresh', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const { shopId } = req.body as { shopId: string };
    await shopService.refreshShopeeToken(req.user.sub, shopId);
    return reply.send({ success: true, data: { message: 'Token refreshed' } });
  });

  app.get('/api/shops/tiktok/auth-url', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const result = await shopService.getTikTokAuthUrl(req.user.sub);
    return reply.send({ success: true, data: result });
  });

  app.get('/api/shops/tiktok/callback', async (req: any, reply) => {
    const { code, state } = req.query;
    if (!code || !state) {
      return reply.status(400).send({ success: false, error: { code: 'MISSING_PARAMS', message: 'Missing OAuth params' } });
    }
    const shop = await shopService.handleTikTokCallback(req.user?.sub ?? '', code, state);
    return reply.send({
      success: true,
      data: {
        shop: {
          id: shop.id,
          platformShopId: shop.platformShopId,
          shopName: shop.shopName,
          platform: shop.platform,
          region: shop.region,
          connectedAt: shop.createdAt.toISOString(),
        },
      },
    });
  });

  app.post('/api/shops/tiktok/refresh', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const { shopId } = req.body as { shopId: string };
    await shopService.refreshTikTokToken(req.user.sub, shopId);
    return reply.send({ success: true, data: { message: 'Token refreshed' } });
  });

  app.delete('/api/shops/:shopId', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    await shopService.disconnectShop(req.user.sub, req.params.shopId);
    return reply.send({ success: true, data: { message: 'Shop disconnected' } });
  });
}

import { prisma } from '../../database/client';
import { encrypt } from '../../utils/crypto';
import { shopeeAuth } from '../../integrations/shopee/shopee.auth';
import { tiktokAuth } from '../../integrations/tiktok/tiktok.auth';
import type { ShopConnection } from '@prisma/client';

export class ShopService {
  async listShops(userId: string): Promise<Array<{
    id: string; platformShopId: string; shopName: string; platform: string;
    region: string; status: string; productCount: number; connectedAt: string; lastSyncAt: string | null;
  }>> {
    const shops = await prisma.shopConnection.findMany({
      where: { userId, disconnectedAt: null },
      orderBy: { createdAt: 'asc' },
    });

    return shops.map((s) => ({
      id: s.id,
      platformShopId: s.platformShopId,
      shopName: s.shopName,
      platform: s.platform,
      region: s.region,
      status: s.status,
      productCount: 0,
      connectedAt: s.createdAt.toISOString(),
      lastSyncAt: s.lastSyncAt?.toISOString() ?? null,
    }));
  }

  async getShopeeAuthUrl(userId: string): Promise<{ url: string; state: string }> {
    return shopeeAuth.generateAuthUrl(userId);
  }

  async getTikTokAuthUrl(userId: string): Promise<{ url: string; state: string }> {
    return tiktokAuth.generateAuthUrl(userId);
  }

  async handleShopeeCallback(userId: string, code: string, shopId: string, state: string): Promise<ShopConnection> {
    return shopeeAuth.handleCallback(userId, code, shopId, state);
  }

  async handleTikTokCallback(userId: string, code: string, state: string): Promise<ShopConnection> {
    return tiktokAuth.handleCallback(userId, code, state);
  }

  async refreshShopeeToken(userId: string, shopId: string): Promise<void> {
    const shop = await prisma.shopConnection.findFirst({ where: { id: shopId, userId } });
    if (!shop) throw new Error('SHOP_NOT_FOUND');

    const { accessToken, refreshToken, expiresAt } = await shopeeAuth.refreshAccessToken(shop);
    await prisma.shopConnection.update({
      where: { id: shopId },
      data: {
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
        status: 'ACTIVE',
      },
    });
  }

  async refreshTikTokToken(userId: string, shopId: string): Promise<void> {
    const shop = await prisma.shopConnection.findFirst({ where: { id: shopId, userId } });
    if (!shop) throw new Error('SHOP_NOT_FOUND');

    const { accessToken, refreshToken, expiresAt } = await tiktokAuth.refreshAccessToken(shop);
    await prisma.shopConnection.update({
      where: { id: shopId },
      data: {
        accessTokenEnc: encrypt(accessToken),
        refreshTokenEnc: encrypt(refreshToken),
        tokenExpiresAt: expiresAt,
        status: 'ACTIVE',
      },
    });
  }

  async disconnectShop(userId: string, shopId: string): Promise<void> {
    await prisma.shopConnection.update({
      where: { id: shopId, userId },
      data: { status: 'DISCONNECTED', disconnectedAt: new Date() },
    });
  }
}

export const shopService = new ShopService();

import { prisma } from '../../database/client';
import { getCache, setCache, invalidateCache, CACHE_TTL } from '../../cache/redis';
import { shopeeProduct } from '../../integrations/shopee/shopee.product';
import { tiktokProduct } from '../../integrations/tiktok/tiktok.product';
import { decrypt } from '../../utils/crypto';

type ProductStatus = 'ACTIVE' | 'INACTIVE' | 'SOLD_OUT' | 'ALL';

function normalizeShopeeStatus(status: string): 'ACTIVE' | 'INACTIVE' | 'SOLD_OUT' {
  if (status === 'NORMAL') return 'ACTIVE';
  if (status === 'SOLD_OUT') return 'SOLD_OUT';
  return 'INACTIVE';
}

function normalizeTikTokStatus(status: string): 'ACTIVE' | 'INACTIVE' | 'SOLD_OUT' {
  if (status === 'ACTIVATE') return 'ACTIVE';
  if (status === 'SOLD_OUT') return 'SOLD_OUT';
  return 'INACTIVE';
}

export class ProductService {
  async listProducts(params: {
    userId: string;
    shopId: string;
    page: number;
    limit: number;
    search?: string;
    status?: ProductStatus;
  }): Promise<{
    data: { products: unknown[] };
    meta: { page: number; limit: number; total: number; hasMore: boolean };
  }> {
    const { userId, shopId, page, limit, search, status } = params;

    const shop = await prisma.shopConnection.findFirst({
      where: { id: shopId, userId, disconnectedAt: null },
    });
    if (!shop) throw new Error('SHOP_NOT_FOUND');

    const filtersHash = JSON.stringify({ search, status });
    const cacheKey = `product_list:${shopId}:${page}:${Buffer.from(filtersHash).toString('base64').slice(0, 16)}`;
    const cached = await getCache<{ data: { products: unknown[] }; meta: { page: number; limit: number; total: number; hasMore: boolean } }>(cacheKey);
    if (cached) return cached;

    let products: unknown[] = [];
    let total = 0;
    let hasMore = false;

    if (shop.platform === 'SHOPEE') {
      const result = await shopeeProduct.getItemList(shop, page, limit, search);
      if (result.items.length > 0) {
        const itemIds = result.items.map((i) => i.item_id);
        const details = await shopeeProduct.getItemBaseInfo(shop, itemIds);
        products = (details as any[]).map((item: any) => ({
          id: item.item_id?.toString() ?? '',
          platformProductId: item.item_id?.toString() ?? '',
          name: item.item_name ?? '',
          coverImage: item.image?.image_url_list?.[0] ?? '',
          status: normalizeShopeeStatus(item.item_status ?? ''),
          totalStock: (item.stock_info_v2?.summary_info?.total_reserved_stock ?? 0) + (item.stock_info_v2?.summary_info?.total_available_stock ?? 0),
          priceRange: {
            min: Number(item.price_info?.[0]?.current_price ?? 0),
            max: Number(item.price_info?.[item.price_info.length - 1]?.current_price ?? 0),
            currency: 'IDR',
          },
          variantCount: item.model?.length ?? 1,
          updatedAt: new Date((item.update_time ?? 0) * 1000).toISOString(),
        }));
      }
      total = result.total_count;
      hasMore = result.has_next_page;
    } else {
      const result = await tiktokProduct.getProductList(shop, page, limit, search);
      products = (result.products as any[]).map((item: any) => ({
        id: item.id ?? '',
        platformProductId: item.id ?? '',
        name: item.title ?? '',
        coverImage: item.main_images?.[0]?.urls?.[0] ?? '',
        status: normalizeTikTokStatus(item.status ?? ''),
        totalStock: item.skus?.reduce((acc: number, s: any) => acc + (s.inventory?.[0]?.quantity ?? 0), 0) ?? 0,
        priceRange: {
          min: Number(item.skus?.[0]?.price?.sale_price ?? 0),
          max: Number(item.skus?.[item.skus.length - 1]?.price?.sale_price ?? 0),
          currency: 'IDR',
        },
        variantCount: item.skus?.length ?? 1,
        updatedAt: item.update_time ?? new Date().toISOString(),
      }));
      total = result.total_count;
      hasMore = result.has_more;
    }

    if (status && status !== 'ALL') {
      products = products.filter((p: any) => p.status === status);
    }

    const result = { data: { products }, meta: { page, limit, total, hasMore } };
    await setCache(cacheKey, result, CACHE_TTL.PRODUCT_LIST);
    return result;
  }

  async getProductDetail(userId: string, productId: string, shopId: string): Promise<unknown> {
    const shop = await prisma.shopConnection.findFirst({
      where: { id: shopId, userId, disconnectedAt: null },
    });
    if (!shop) throw new Error('SHOP_NOT_FOUND');

    const cacheKey = `product:${shopId}:${productId}`;
    const cached = await getCache(cacheKey);
    if (cached) return cached;

    let detail: unknown = null;

    if (shop.platform === 'SHOPEE') {
      const items = await shopeeProduct.getItemBaseInfo(shop, [Number(productId)]);
      const item = (items as any[])[0];
      if (!item) throw new Error('PRODUCT_NOT_FOUND');

      detail = {
        id: item.item_id?.toString() ?? '',
        platformProductId: item.item_id?.toString() ?? '',
        name: item.item_name ?? '',
        description: item.description ?? '',
        images: (item.image?.image_url_list ?? []).map((url: string, i: number) => ({
          imageId: `img_${i}`,
          url,
          order: i,
        })),
        status: normalizeShopeeStatus(item.item_status ?? ''),
        category: item.category_id?.toString() ?? '',
        variants: (item.model ?? []).map((m: any) => ({
          variantId: m.model_id?.toString() ?? '',
          name: m.model_name ?? '',
          sku: m.model_sku ?? '',
          stock: m.stock_info_v2?.summary_info?.total_available_stock ?? 0,
          price: Number(m.price_info?.[0]?.current_price ?? 0),
          originalPrice: Number(m.price_info?.[0]?.original_price ?? 0),
          currency: 'IDR',
          attributes: {},
        })),
        createdAt: new Date((item.create_time ?? 0) * 1000).toISOString(),
        updatedAt: new Date((item.update_time ?? 0) * 1000).toISOString(),
      };
    } else {
      const item = await tiktokProduct.getProductDetail(shop, productId) as any;
      if (!item) throw new Error('PRODUCT_NOT_FOUND');

      detail = {
        id: item.id ?? '',
        platformProductId: item.id ?? '',
        name: item.title ?? '',
        description: item.description ?? '',
        images: (item.main_images ?? []).map((img: any, i: number) => ({
          imageId: img.uri ?? `img_${i}`,
          url: img.urls?.[0] ?? '',
          order: i,
        })),
        status: normalizeTikTokStatus(item.status ?? ''),
        category: item.category_chains?.[0]?.id ?? '',
        variants: (item.skus ?? []).map((sku: any) => ({
          variantId: sku.id ?? '',
          name: sku.sales_attributes?.map((a: any) => a.value_name).join(' / ') ?? '',
          sku: sku.seller_sku ?? '',
          stock: sku.inventory?.[0]?.quantity ?? 0,
          price: Number(sku.price?.sale_price ?? 0),
          originalPrice: Number(sku.price?.tax_exclusive_price ?? sku.price?.sale_price ?? 0),
          currency: 'IDR',
          attributes: Object.fromEntries(
            (sku.sales_attributes ?? []).map((a: any) => [a.attribute_name, a.value_name]),
          ),
        })),
        createdAt: item.create_time ?? new Date().toISOString(),
        updatedAt: item.update_time ?? new Date().toISOString(),
      };
    }

    await setCache(cacheKey, detail, CACHE_TTL.PRODUCT_DETAIL);
    return detail;
  }

  async syncProducts(userId: string, shopId: string): Promise<{ synced: number; message: string }> {
    const shop = await prisma.shopConnection.findFirst({
      where: { id: shopId, userId, disconnectedAt: null },
    });
    if (!shop) throw new Error('SHOP_NOT_FOUND');

    await invalidateCache(`product_list:${shopId}:*`);
    await invalidateCache(`product:${shopId}:*`);

    let synced = 0;

    if (shop.platform === 'SHOPEE') {
      const result = await shopeeProduct.getItemList(shop, 1, 50);
      if (result.items.length > 0) {
        const details = await shopeeProduct.getItemBaseInfo(shop, result.items.map((i) => i.item_id));

        for (const item of details as any[]) {
          await prisma.productCache.upsert({
            where: { shopConnectionId_platformProductId: { shopConnectionId: shopId, platformProductId: item.item_id?.toString() ?? '' } },
            create: {
              shopConnectionId: shopId,
              platformProductId: item.item_id?.toString() ?? '',
              name: item.item_name ?? '',
              coverImageUrl: item.image?.image_url_list?.[0],
              status: normalizeShopeeStatus(item.item_status ?? ''),
              totalStock: 0,
              minPrice: item.price_info?.[0]?.current_price ?? 0,
              maxPrice: item.price_info?.[item.price_info.length - 1]?.current_price ?? 0,
              rawData: item,
            },
            update: {
              name: item.item_name ?? '',
              status: normalizeShopeeStatus(item.item_status ?? ''),
              rawData: item,
              cachedAt: new Date(),
            },
          });
          synced++;
        }
      }
    }

    await prisma.shopConnection.update({
      where: { id: shopId },
      data: { lastSyncAt: new Date() },
    });

    return { synced, message: `Synced ${synced} products successfully` };
  }
}

export const productService = new ProductService();

