import type { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { bulkService } from './bulk.service';

const BulkStockSchema = z.object({
  shopId: z.string(),
  items: z.array(z.object({
    productId: z.string(),
    variantId: z.string(),
    stock: z.number().min(0).max(999999),
  })).max(200),
});

const BulkPriceSchema = z.object({
  shopId: z.string(),
  items: z.array(z.object({
    productId: z.string(),
    variantId: z.string(),
    price: z.number().min(1),
    originalPrice: z.number().optional(),
  })).max(200),
});

export async function bulkRoutes(app: FastifyInstance): Promise<void> {
  app.post('/api/bulk/stock', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const input = BulkStockSchema.parse(req.body);
    const job = await bulkService.createStockJob(req.user.sub, input);
    return reply.status(202).send({ success: true, data: job });
  });

  app.post('/api/bulk/price', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const input = BulkPriceSchema.parse(req.body);
    const job = await bulkService.createPriceJob(req.user.sub, input);
    return reply.status(202).send({ success: true, data: job });
  });

  app.get('/api/bulk/history', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const { shopId, limit } = req.query as { shopId?: string; limit?: string };
    const jobs = await bulkService.getHistory(req.user.sub, shopId, limit ? Number(limit) : 20);
    return reply.send({ success: true, data: { jobs } });
  });

  app.get('/api/bulk/:jobId/status', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const job = await bulkService.getJobStatus(req.user.sub, req.params.jobId);
    return reply.send({ success: true, data: job });
  });
}

import { prisma } from '../../database/client';
import { Queue } from 'bullmq';
import { redis } from '../../cache/redis';

const bulkQueue = new Queue('bulk-update', { connection: redis as any });

export class BulkService {
  async createStockJob(
    userId: string,
    input: { shopId: string; items: Array<{ productId: string; variantId: string; stock: number }> },
  ): Promise<{ jobId: string; status: string; total: number; estimatedSeconds: number }> {
    const job = await prisma.bulkJob.create({
      data: {
        userId,
        shopConnectionId: input.shopId,
        type: 'STOCK',
        totalItems: input.items.length,
        payload: input.items,
      },
    });

    const queueJob = await bulkQueue.add('process-stock', {
      jobId: job.id,
      userId,
      shopId: input.shopId,
      items: input.items,
    });

    await prisma.bulkJob.update({
      where: { id: job.id },
      data: { queueJobId: queueJob.id },
    });

    return {
      jobId: job.id,
      status: 'QUEUED',
      total: input.items.length,
      estimatedSeconds: Math.max(5, Math.ceil(input.items.length / 50) * 12),
    };
  }

  async createPriceJob(
    userId: string,
    input: { shopId: string; items: Array<{ productId: string; variantId: string; price: number; originalPrice?: number }> },
  ): Promise<{ jobId: string; status: string; total: number; estimatedSeconds: number }> {
    const job = await prisma.bulkJob.create({
      data: {
        userId,
        shopConnectionId: input.shopId,
        type: 'PRICE',
        totalItems: input.items.length,
        payload: input.items,
      },
    });

    const queueJob = await bulkQueue.add('process-price', {
      jobId: job.id,
      userId,
      shopId: input.shopId,
      items: input.items,
    });

    await prisma.bulkJob.update({
      where: { id: job.id },
      data: { queueJobId: queueJob.id },
    });

    return {
      jobId: job.id,
      status: 'QUEUED',
      total: input.items.length,
      estimatedSeconds: Math.max(5, Math.ceil(input.items.length / 50) * 12),
    };
  }

  async getJobStatus(userId: string, jobId: string): Promise<{
    jobId: string; status: string; progress: number; total: number;
    successCount: number; failedCount: number; errors: unknown;
    startedAt: string | null; completedAt: string | null;
  }> {
    const job = await prisma.bulkJob.findFirst({ where: { id: jobId, userId } });
    if (!job) throw new Error('JOB_NOT_FOUND');

    return {
      jobId: job.id,
      status: job.status,
      progress: job.progress,
      total: job.totalItems,
      successCount: job.successCount,
      failedCount: job.failedCount,
      errors: job.errors ?? [],
      startedAt: job.startedAt?.toISOString() ?? null,
      completedAt: job.completedAt?.toISOString() ?? null,
    };
  }

  async getHistory(
    userId: string,
    shopId?: string,
    limit = 20,
  ): Promise<Array<{
    jobId: string; type: string; status: string; total: number;
    successCount: number; failedCount: number; createdAt: string;
  }>> {
    const where: Record<string, unknown> = { userId };
    if (shopId) where.shopConnectionId = shopId;

    const jobs = await prisma.bulkJob.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: limit,
      select: {
        id: true, type: true, status: true, totalItems: true,
        successCount: true, failedCount: true, createdAt: true,
      },
    });

    return jobs.map((j) => ({
      jobId: j.id,
      type: j.type,
      status: j.status,
      total: j.totalItems,
      successCount: j.successCount,
      failedCount: j.failedCount,
      createdAt: j.createdAt.toISOString(),
    }));
  }
}

export const bulkService = new BulkService();

import type { FastifyInstance } from 'fastify';
import { z } from 'zod';
import { shopeeProduct } from '../../integrations/shopee/shopee.product';
import { tiktokProduct } from '../../integrations/tiktok/tiktok.product';
import { prisma } from '../../database/client';

const UpdateImagesSchema = z.object({
  shopId: z.string(),
  images: z.array(z.object({ imageId: z.string(), order: z.number().int().min(0) })),
});

export async function imageRoutes(app: FastifyInstance): Promise<void> {
  app.post('/api/images/upload', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const data = await req.file();
    if (!data) {
      return reply.status(400).send({ success: false, error: { code: 'VALIDATION_ERROR', message: 'No file uploaded' } });
    }

    const { shopId, platform } = data.fields as Record<string, { value: string }>;
    const shopIdVal = shopId?.value ?? '';
    const platformVal = platform?.value ?? '';

    const shop = await prisma.shopConnection.findFirst({
      where: { id: shopIdVal, userId: req.user.sub },
    });
    if (!shop) {
      return reply.status(404).send({ success: false, error: { code: 'SHOP_NOT_FOUND', message: 'Shop not found' } });
    }

    const chunks: Buffer[] = [];
    for await (const chunk of data.file) {
      chunks.push(chunk as Buffer);
    }
    const buffer = Buffer.concat(chunks);
    const mimeType = data.mimetype;

    let result: { imageId: string; imageUrl: string; width: number; height: number };

    if (shop.platform === 'SHOPEE') {
      result = await shopeeProduct.uploadImage(shop, buffer, mimeType);
    } else {
      result = await tiktokProduct.uploadImage(shop, buffer, mimeType);
    }

    return reply.send({ success: true, data: result });
  });

  app.patch('/api/products/:productId/images', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const input = UpdateImagesSchema.parse(req.body);
    const { productId } = req.params;

    const shop = await prisma.shopConnection.findFirst({
      where: { id: input.shopId, userId: req.user.sub },
    });
    if (!shop) {
      return reply.status(404).send({ success: false, error: { code: 'SHOP_NOT_FOUND', message: 'Shop not found' } });
    }

    const sorted = [...input.images].sort((a, b) => a.order - b.order);
    const imageIds = sorted.map((i) => i.imageId);

    if (shop.platform === 'SHOPEE') {
      const { createShopeeClient } = await import('../../integrations/shopee/shopee.client');
      const client = createShopeeClient(shop);
      await client.post('/api/v2/product/update_item', {
        item_id: Number(productId),
        image: { image_id_list: imageIds },
      });
    } else {
      const { createTikTokClient } = await import('../../integrations/tiktok/tiktok.client');
      const client = createTikTokClient(shop);
      await client.put(`/product/202309/products/${productId}`, {
        main_images: imageIds.map((id) => ({ uri: id })),
      });
    }

    await prisma.updateLog.create({
      data: {
        shopConnectionId: shop.id,
        platformProductId: productId,
        updateType: 'IMAGE',
        status: 'SUCCESS',
        newValue: { imageIds },
      },
    });

    return reply.send({ success: true, data: { message: 'Images updated' } });
  });
}

import type { FastifyInstance } from 'fastify';
import crypto from 'crypto';
import { prisma } from '../../database/client';
import { redis } from '../../cache/redis';
import { invalidateCache } from '../../cache/redis';
import { logger } from '../../utils/logger';

function verifyShopeeSignature(body: string, authorization: string): boolean {
  const partnerKey = process.env.SHOPEE_PARTNER_KEY ?? '';
  const expected = crypto.createHmac('sha256', partnerKey).update(body).digest('hex');
  return expected === authorization;
}

function verifyTikTokSignature(payload: string, timestamp: string, appSecret: string, signature: string): boolean {
  const toSign = `${timestamp}${payload}`;
  const expected = crypto.createHmac('sha256', appSecret).update(toSign).digest('hex');
  return expected === signature;
}

export async function webhookRoutes(app: FastifyInstance): Promise<void> {
  app.post('/webhooks/shopee', async (req, reply) => {
    const authorization = req.headers.authorization ?? '';
    const rawBody = JSON.stringify(req.body);

    if (!verifyShopeeSignature(rawBody, authorization)) {
      logger.warn('Shopee webhook signature mismatch');
    }

    const body = req.body as Record<string, unknown>;
    const eventType = String(body.code ?? body.event_type ?? 'unknown');
    const shopId = String(body.shopid ?? body.shop_id ?? '');

    try {
      await prisma.webhookEvent.create({
        data: {
          platform: 'SHOPEE',
          eventType,
          payload: body,
          signature: authorization,
        },
      });

      await invalidateCache(`product_list:*`);
      if (shopId) {
        await redis.publish(`lookup:sse:all`, JSON.stringify({
          type: 'shopee_webhook',
          eventType,
          shopId,
        }));
      }
    } catch (err) {
      logger.error({ err }, 'Failed to process Shopee webhook');
    }

    return reply.status(200).send('OK');
  });

  app.post('/webhooks/tiktok', async (req, reply) => {
    const appSecret = process.env.TIKTOK_APP_SECRET ?? '';
    const timestamp = req.headers['x-tts-timestamp'] as string ?? '';
    const signature = req.headers['x-tts-signature'] as string ?? '';
    const rawBody = JSON.stringify(req.body);

    if (!verifyTikTokSignature(rawBody, timestamp, appSecret, signature)) {
      logger.warn('TikTok webhook signature mismatch');
    }

    const body = req.body as Record<string, unknown>;
    const eventType = String(body.type ?? 'unknown');

    try {
      await prisma.webhookEvent.create({
        data: {
          platform: 'TIKTOK',
          eventType,
          payload: body,
          signature,
        },
      });

      await invalidateCache(`product_list:*`);
      await redis.publish('lookup:sse:all', JSON.stringify({
        type: 'tiktok_webhook',
        eventType,
        data: body.data,
      }));
    } catch (err) {
      logger.error({ err }, 'Failed to process TikTok webhook');
    }

    return reply.status(200).send('OK');
  });

  app.get('/api/events/stream', { onRequest: [app.authenticate] }, async (req: any, reply) => {
    const userId: string = req.user.sub;

    reply.raw.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
      'X-Accel-Buffering': 'no',
    });

    reply.raw.write(`data: ${JSON.stringify({ type: 'connected', userId })}\n\n`);

    const subscriber = redis.duplicate();
    await subscriber.subscribe(`lookup:sse:${userId}`, 'lookup:sse:all');

    subscriber.on('message', (_channel: string, message: string) => {
      try {
        const event = JSON.parse(message);
        const eventName = event.type ?? 'update';
        reply.raw.write(`event: ${eventName}\ndata: ${JSON.stringify(event)}\n\n`);
      } catch {
        // ignore parse errors
      }
    });

    const keepalive = setInterval(() => {
      if (!reply.raw.writableEnded) {
        reply.raw.write(': keepalive\n\n');
      }
    }, 15000);

    req.raw.on('close', async () => {
      clearInterval(keepalive);
      await subscriber.unsubscribe();
      subscriber.disconnect();
      reply.raw.end();
    });
  });
}

import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { Colors } from '@/constants/colors';

type BadgeVariant = 'success' | 'warning' | 'danger' | 'info' | 'neutral' | 'shopee' | 'tiktok';

const BG: Record<BadgeVariant, string> = {
  success: Colors.successLight,
  warning: Colors.warningLight,
  danger: Colors.dangerLight,
  info: Colors.infoLight,
  neutral: Colors.inputBg,
  shopee: Colors.shopeeLight,
  tiktok: Colors.tiktokLight,
};

const TEXT_CLR: Record<BadgeVariant, string> = {
  success: Colors.success,
  warning: Colors.warning,
  danger: Colors.danger,
  info: Colors.info,
  neutral: Colors.textSecondary,
  shopee: Colors.shopee,
  tiktok: Colors.tiktokPink,
};

interface BadgeProps {
  label: string;
  variant?: BadgeVariant;
}

export function Badge({ label, variant = 'neutral' }: BadgeProps) {
  return (
    <View style={[styles.container, { backgroundColor: BG[variant] }]}>
      <Text style={[styles.text, { color: TEXT_CLR[variant] }]}>{label}</Text>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    height: 20,
