import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { shopApi } from '@/api/shop.api';
import type { Shop } from '@/types';

export function useShops() {
  return useQuery<Shop[]>({
    queryKey: ['shops'],
    queryFn: () => shopApi.listShops(),
    staleTime: 60_000,
  });
}

export function useConnectShop() {
  const queryClient = useQueryClient();

  const getAuthUrl = useMutation({
    mutationFn: (platform: 'SHOPEE' | 'TIKTOK') => shopApi.getAuthUrl(platform),
  });

  const disconnect = useMutation({
    mutationFn: (shopId: string) => shopApi.disconnectShop(shopId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['shops'] });
    },
  });

  const refreshTokens = useMutation({
    mutationFn: (shopId: string) => shopApi.refreshTokens(shopId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['shops'] });
    },
  });

  return { getAuthUrl, disconnect, refreshTokens };
}

