import { useState, useEffect, useRef } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { bulkApi } from '@/api/bulk.api';
import type { BulkJobStatus } from '@/types';

export function useBulkJob() {
  const queryClient = useQueryClient();

  const createStockJob = useMutation({
    mutationFn: bulkApi.createStockJob,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['bulk-history'] });
    },
  });

  const createPriceJob = useMutation({
    mutationFn: bulkApi.createPriceJob,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['bulk-history'] });
    },
  });

  return { createStockJob, createPriceJob };
}

export function useBulkJobStatus(jobId: string | null) {
  const [pollingInterval, setPollingInterval] = useState<number | false>(2000);

  const query = useQuery<BulkJobStatus>({
    queryKey: ['bulk-job', jobId],
    queryFn: () => bulkApi.getJobStatus(jobId!),
    refetchInterval: pollingInterval,
    enabled: !!jobId,
  });

  useEffect(() => {
    const status = query.data?.status;
    if (status === 'COMPLETED' || status === 'FAILED' || status === 'PARTIAL') {
      setPollingInterval(false);
    } else {
      setPollingInterval(2000);
    }
  }, [query.data?.status]);

  return query;
}

export function useBulkHistory(shopId?: string) {
  return useQuery({
    queryKey: ['bulk-history', shopId],
    queryFn: () => bulkApi.getHistory(shopId),
    staleTime: 15_000,
  });
}

import { useEffect, useRef, useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useAuthStore } from '@/stores/authStore';
import { API_BASE_URL } from '@/api/client';

type EventHandler = (data: Record<string, unknown>) => void;

export function useRealtimeEvents(handlers?: Partial<Record<string, EventHandler>>) {
  const queryClient = useQueryClient();
  const token = useAuthStore((s) => s.token);
  const esRef = useRef<EventSource | null>(null);
  const stableHandlers = useRef(handlers);
  stableHandlers.current = handlers;

  const defaultHandler = useCallback(
    (type: string, data: Record<string, unknown>) => {
      if (type === 'shopee_webhook' || type === 'tiktok_webhook') {
        queryClient.invalidateQueries({ queryKey: ['products'] });
      }
      stableHandlers.current?.[type]?.(data);
    },
    [queryClient],
  );

  useEffect(() => {
    if (!token) return;

    const url = `${API_BASE_URL}/api/events/stream`;

    try {
      const es = new EventSource(`${url}?token=${token}`);
      esRef.current = es;

      es.onmessage = (e) => {
        try {
          const data = JSON.parse(e.data as string) as Record<string, unknown>;
          defaultHandler(String(data.type ?? 'message'), data);
        } catch {
          // ignore
        }
      };

      es.addEventListener('shopee_webhook', (e: Event) => {
        const messageEvent = e as MessageEvent;
        try {
          const data = JSON.parse(messageEvent.data as string) as Record<string, unknown>;
          defaultHandler('shopee_webhook', data);
        } catch { /* empty */ }
      });

      es.addEventListener('tiktok_webhook', (e: Event) => {
        const messageEvent = e as MessageEvent;
        try {
          const data = JSON.parse(messageEvent.data as string) as Record<string, unknown>;
          defaultHandler('tiktok_webhook', data);
        } catch { /* empty */ }
      });

      return () => {
        es.close();
        esRef.current = null;
      };
    } catch {
      return undefined;
    }
  }, [token, defaultHandler]);
}

import { apiClient } from './client';

export const stockApi = {
  async updateStock(
    productId: string,
    input: { shopId: string; updates: Array<{ variantId: string; stock: number }> },
  ): Promise<{ updated: Array<{ variantId: string; stock: number }>; updatedAt: string }> {
    const data = await apiClient.patch<{
      updated: Array<{ variantId: string; stock: number }>;
      updatedAt: string;
    }>(`/api/products/${productId}/stock`, input);
    return data;
  },
};

import { apiClient } from './client';

export const priceApi = {
  async updatePrice(
    productId: string,
    input: {
      shopId: string;
      updates: Array<{ variantId: string; price: number; originalPrice?: number }>;
    },
  ): Promise<{ updated: typeof input.updates; updatedAt: string }> {
    const data = await apiClient.patch<{
      updated: Array<{ variantId: string; price: number; originalPrice?: number }>;
      updatedAt: string;
    }>(`/api/products/${productId}/price`, input);
    return data;
  },
};

import { API_BASE_URL } from './client';
import { useAuthStore } from '@/stores/authStore';

export interface UploadedImage {
  imageId: string;
  imageUrl: string;
  width: number;
  height: number;
}

export const imageApi = {
  async uploadImage(shopId: string, uri: string, mimeType: string): Promise<UploadedImage> {
    const token = useAuthStore.getState().token;

    const formData = new FormData();
    const filename = uri.split('/').pop() ?? 'image.jpg';
    formData.append('file', { uri, name: filename, type: mimeType } as unknown as Blob);
    formData.append('shopId', shopId);

    const response = await fetch(`${API_BASE_URL}/api/images/upload`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: formData,
    });

    if (!response.ok) {
      const err = (await response.json()) as { error?: { message: string } };
      throw new Error(err.error?.message ?? 'Upload failed');
    }

    const json = (await response.json()) as { data: UploadedImage };
    return json.data;
  },

  async updateProductImages(
    productId: string,
    input: { shopId: string; images: Array<{ imageId: string; order: number }> },
  ): Promise<{ message: string }> {
    const { apiClient } = await import('./client');
    return apiClient.patch<{ message: string }>(`/api/products/${productId}/images`, input);
  },
};

import { apiClient } from './client';
import type { BulkJobStatus, BulkJobSummary } from '@/types';

export const bulkApi = {
  async createStockJob(input: {
    shopId: string;
    items: Array<{ productId: string; variantId: string; stock: number }>;
  }): Promise<{ jobId: string; status: string; total: number; estimatedSeconds: number }> {
    return apiClient.post('/api/bulk/stock', input);
  },

  async createPriceJob(input: {
    shopId: string;
    items: Array<{ productId: string; variantId: string; price: number; originalPrice?: number }>;
  }): Promise<{ jobId: string; status: string; total: number; estimatedSeconds: number }> {
    return apiClient.post('/api/bulk/price', input);
  },

  async getJobStatus(jobId: string): Promise<BulkJobStatus> {
    return apiClient.get(`/api/bulk/${jobId}/status`);
  },

  async getHistory(shopId?: string): Promise<{ jobs: BulkJobSummary[] }> {
    const q = shopId ? `?shopId=${shopId}` : '';
    return apiClient.get(`/api/bulk/history${q}`);
  },
};

import React, { useState } from 'react';
import {
  View, Text, KeyboardAvoidingView, Platform, ScrollView, StyleSheet,
} from 'react-native';
import { useForm, Controller } from 'react-hook-form';
import { Button } from '@/components/atoms/Button';
import { AppTextInput } from '@/components/atoms/AppTextInput';
import { Colors } from '@/constants/colors';
import { useAuthStore } from '@/stores/authStore';
import { authApi } from '@/api/auth.api';
import type { NativeStackScreenProps } from '@react-navigation/native-stack';
import type { AuthStackParamList } from '@/navigation/AuthNavigator';

type Props = NativeStackScreenProps<AuthStackParamList, 'Login'>;

interface LoginForm {
  email: string;
  password: string;
}

export function LoginScreen({ navigation }: Props) {
  const { control, handleSubmit, formState: { errors } } = useForm<LoginForm>();
  const setAuth = useAuthStore((s) => s.setAuth);
  const [apiError, setApiError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const onSubmit = async (values: LoginForm) => {
    setApiError('');
    setIsLoading(true);
    try {
      const result = await authApi.login(values.email, values.password);
      setAuth(result.token, result.user);
    } catch (err) {
      setApiError(err instanceof Error ? err.message : 'Login gagal');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <KeyboardAvoidingView
      style={styles.flex}
      behavior={Platform.OS === 'ios' ? 'padding' : undefined}
    >
      <ScrollView contentContainerStyle={styles.container} keyboardShouldPersistTaps="handled">
        <View style={styles.header}>
          <Text style={styles.logo}>LookUp</Text>
          <Text style={styles.subtitle}>Kelola stok & harga multi-platform</Text>
        </View>

        <View style={styles.form}>
          <Controller
            control={control}
            name="email"
            rules={{ required: 'Email wajib diisi', pattern: { value: /\S+@\S+\.\S+/, message: 'Email tidak valid' } }}
            render={({ field }) => (
              <AppTextInput
                label="Email"
                placeholder="nama@email.com"
                keyboardType="email-address"
                autoCapitalize="none"
                value={field.value}
                onChangeText={field.onChange}
                error={errors.email?.message}
              />
            )}
          />

          <Controller
            control={control}
            name="password"
            rules={{ required: 'Password wajib diisi', minLength: { value: 6, message: 'Minimal 6 karakter' } }}
            render={({ field }) => (
              <AppTextInput
                label="Password"
                placeholder="••••••"
                secureTextEntry
                value={field.value}
                onChangeText={field.onChange}
                error={errors.password?.message}
              />
            )}
          />

          {!!apiError && <Text style={styles.apiError}>{apiError}</Text>}

          <Button
            label="Masuk"
            onPress={handleSubmit(onSubmit)}
            variant="primary"
            loading={isLoading}
          />

          <Button
            label="Belum punya akun? Daftar"
            onPress={() => navigation.navigate('Register')}
            variant="ghost"
          />
        </View>
      </ScrollView>
    </KeyboardAvoidingView>
  );
}

