     1→// src/api/client.ts — Base Axios instance with JWT auth + auto-refresh
     2→
     3→import axios, { type AxiosInstance, type InternalAxiosRequestConfig } from 'axios';
     4→import * as SecureStore from 'expo-secure-store';
     5→import { API_URL } from '@/constants';
     6→
     7→const REFRESH_TOKEN_KEY = 'lookup_refresh_token';
     8→const ACCESS_TOKEN_KEY = 'lookup_access_token';
     9→
    10→// In-memory access token (never stored to disk)
    11→let inMemoryAccessToken: string | null = null;
    12→
    13→export function setAccessToken(token: string) {
    14→  inMemoryAccessToken = token;
    15→}
    16→
    17→export function getAccessToken(): string | null {
    18→  return inMemoryAccessToken;
    19→}
    20→
    21→export async function storeRefreshToken(token: string) {
    22→  await SecureStore.setItemAsync(REFRESH_TOKEN_KEY, token);
    23→}
    24→
    25→export async function getStoredRefreshToken(): Promise<string | null> {
    26→  return SecureStore.getItemAsync(REFRESH_TOKEN_KEY);
    27→}
    28→
    29→export async function clearTokens() {
    30→  inMemoryAccessToken = null;
    31→  await SecureStore.deleteItemAsync(REFRESH_TOKEN_KEY);
    32→}
    33→
    34→// ─── Base Client ─────────────────────────────────────────────────────────────
    35→
    36→export const apiClient: AxiosInstance = axios.create({
    37→  baseURL: API_URL,
    38→  timeout: 15_000,
    39→  headers: { 'Content-Type': 'application/json' },
    40→});
    41→
    42→// Attach access token on every request
    43→apiClient.interceptors.request.use((config: InternalAxiosRequestConfig) => {
    44→  const token = getAccessToken();
    45→  if (token) {
    46→    config.headers.Authorization = `Bearer ${token}`;
    47→  }
    48→  return config;
    49→});
    50→
    51→// Auto-refresh on 401
    52→let isRefreshing = false;
    53→let pendingRequests: Array<(token: string) => void> = [];
    54→
    55→apiClient.interceptors.response.use(
    56→  (res) => res,
    57→  async (error) => {
    58→    const originalRequest = error.config;
    59→
    60→    if (error.response?.status !== 401 || originalRequest._retry) {
    61→      return Promise.reject(error);
    62→    }
    63→
    64→    if (isRefreshing) {
    65→      return new Promise((resolve) => {
    66→        pendingRequests.push((token: string) => {
    67→          originalRequest.headers.Authorization = `Bearer ${token}`;
    68→          resolve(apiClient(originalRequest));
    69→        });
    70→      });
    71→    }
    72→
    73→    originalRequest._retry = true;
    74→    isRefreshing = true;
    75→
    76→    try {
    77→      const refreshToken = await getStoredRefreshToken();
    78→      if (!refreshToken) throw new Error('No refresh token');
    79→
    80→      const { data } = await axios.post(`${API_URL}/api/auth/refresh`, { refreshToken });
    81→      const { accessToken, refreshToken: newRefreshToken } = data.data;
    82→
    83→      setAccessToken(accessToken);
    84→      await storeRefreshToken(newRefreshToken);
    85→
    86→      pendingRequests.forEach((cb) => cb(accessToken));
    87→      pendingRequests = [];
    88→
    89→      originalRequest.headers.Authorization = `Bearer ${accessToken}`;
    90→      return apiClient(originalRequest);
    91→    } catch {
    92→      pendingRequests = [];
    93→      await clearTokens();
    94→      // Trigger logout via event or store reset
    95→      return Promise.reject(error);
    96→    } finally {
    97→      isRefreshing = false;
    98→    }
    99→  }
   100→);
