import React, { useState } from 'react';
import {
  View, Text, KeyboardAvoidingView, Platform, ScrollView, StyleSheet, TouchableOpacity,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useNavigation } from '@react-navigation/native';
import type { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { Button } from '@/components/atoms/Button';
import { AppTextInput } from '@/components/atoms/AppTextInput';
import { Colors } from '@/constants';
import { authApi } from '@/api/auth';
import { useAuthStore } from '@/stores/authStore';
import type { RootStackParamList } from '@/types';

type Nav = NativeStackNavigationProp<RootStackParamList>;

export function RegisterScreen() {
  const navigation = useNavigation<Nav>();
  const { setAuth } = useAuthStore();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [apiError, setApiError] = useState('');
  const [loading, setLoading] = useState(false);

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    if (!name.trim()) newErrors.name = 'Nama wajib diisi';
    if (!email.trim()) newErrors.email = 'Email wajib diisi';
    else if (!/\S+@\S+\.\S+/.test(email)) newErrors.email = 'Email tidak valid';
    if (!password) newErrors.password = 'Password wajib diisi';
    else if (password.length < 8) newErrors.password = 'Minimal 8 karakter';
    if (password !== confirmPassword) newErrors.confirmPassword = 'Password tidak cocok';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleRegister = async () => {
    if (!validate()) return;
    setApiError('');
    setLoading(true);
    try {
      const result = await authApi.register({ name, email, password });
      await setAuth(result.user, result.accessToken, result.refreshToken);
    } catch {
      setApiError('Registrasi gagal. Email mungkin sudah digunakan.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.safe} edges={['top', 'bottom']}>
      <KeyboardAvoidingView style={styles.flex} behavior={Platform.OS === 'ios' ? 'padding' : undefined}>
        <ScrollView contentContainerStyle={styles.container} keyboardShouldPersistTaps="handled">
          <View style={styles.header}>
            <Text style={styles.title}>Buat Akun</Text>
            <Text style={styles.subtitle}>Mulai kelola toko Shopee & TikTok-mu</Text>
          </View>

          <View style={styles.form}>
            <AppTextInput
              label="Nama Lengkap"
              placeholder="Budi Santoso"
              value={name}
              onChangeText={setName}
              error={errors.name}
              autoCapitalize="words"
            />
            <AppTextInput
              label="Email"
              placeholder="nama@email.com"
              value={email}
              onChangeText={setEmail}
              error={errors.email}
              keyboardType="email-address"
              autoCapitalize="none"
            />
            <AppTextInput
              label="Password"
              placeholder="Min. 8 karakter"
              value={password}
              onChangeText={setPassword}
              error={errors.password}
              secureTextEntry
            />
            <AppTextInput
              label="Konfirmasi Password"
              placeholder="Ulangi password"
              value={confirmPassword}
              onChangeText={setConfirmPassword}
              error={errors.confirmPassword}
              secureTextEntry
            />

            {!!apiError && <Text style={styles.apiError}>{apiError}</Text>}

            <Button label="Daftar" onPress={handleRegister} loading={loading} fullWidth />

            <TouchableOpacity onPress={() => navigation.goBack()} style={styles.loginLink}>
              <Text style={styles.loginText}>
                Sudah punya akun? <Text style={styles.loginHighlight}>Masuk</Text>
              </Text>
            </TouchableOpacity>
          </View>
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: Colors.white },
  flex: { flex: 1 },
  container: { flexGrow: 1, padding: 24, gap: 32 },
  header: { marginTop: 24, gap: 8 },
  title: { fontSize: 28, fontWeight: '800', color: Colors.heading },
  subtitle: { fontSize: 14, color: Colors.textSecondary },
  form: { gap: 14 },
  apiError: { fontSize: 13, color: Colors.danger, textAlign: 'center' },
  loginLink: { alignItems: 'center', marginTop: 8 },
  loginText: { fontSize: 14, color: Colors.textSecondary },
  loginHighlight: { color: Colors.primary, fontWeight: '600' },
});

import React from 'react';
import {
  View, Text, ScrollView, TouchableOpacity, StyleSheet, RefreshControl,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useNavigation } from '@react-navigation/native';
import type { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { useQuery } from '@tanstack/react-query';
import { Feather } from '@expo/vector-icons';
import { SummaryCard } from '@/components/organisms/SummaryCard';
import { JobStatusCard } from '@/components/molecules/JobStatusCard';
import { ShopTag } from '@/components/molecules/ShopTag';
import { Skeleton } from '@/components/atoms/Skeleton';
import { Colors } from '@/constants';
import { QUERY_KEYS } from '@/constants/queryKeys';
import { useAuthStore } from '@/stores/authStore';
import { useShopStore } from '@/stores/shopStore';
import { shopsApi } from '@/api/shops';
import { bulkApi } from '@/api/index';
import type { RootStackParamList } from '@/types';

type Nav = NativeStackNavigationProp<RootStackParamList>;

export function HomeScreen() {
  const navigation = useNavigation<Nav>();
  const user = useAuthStore((s) => s.user);
  const { setShops, shops, activeShopId } = useShopStore();

  const { isRefetching, refetch } = useQuery({
    queryKey: QUERY_KEYS.shops(),
    queryFn: async () => {
      const result = await shopsApi.list();
      setShops(result);
      return result;
    },
    staleTime: 60_000,
  });

  const { data: historyData } = useQuery({
    queryKey: QUERY_KEYS.bulkHistory(activeShopId ?? ''),
    queryFn: () => bulkApi.getHistory(activeShopId ?? undefined),
    enabled: !!activeShopId,
    staleTime: 15_000,
  });

  const recentJobs = (historyData ?? []).slice(0, 3);
  const activeShop = shops.find((s) => s.id === activeShopId);

  const statItems = [
    { icon: 'shopping-bag' as const, label: 'Toko Aktif', value: shops.filter((s) => s.status === 'ACTIVE').length, color: Colors.primary },
    { icon: 'package' as const, label: 'Total Produk', value: shops.reduce((sum, s) => sum + (s.productCount ?? 0), 0) },
    { icon: 'alert-triangle' as const, label: 'Token Expired', value: shops.filter((s) => s.status === 'TOKEN_EXPIRED').length, color: Colors.warning },
  ];

  return (
    <SafeAreaView style={styles.safe} edges={['top']}>
      <ScrollView
        contentContainerStyle={styles.content}
        refreshControl={
          <RefreshControl refreshing={isRefetching} onRefresh={refetch} tintColor={Colors.primary} />
        }
      >
        {/* Header */}
        <View style={styles.header}>
          <View>
            <Text style={styles.greeting}>Halo, {user?.name?.split(' ')[0] ?? 'Seller'}!</Text>
            <Text style={styles.subGreeting}>Selamat datang di LookUp</Text>
          </View>
          <TouchableOpacity
            style={styles.shopsBtn}
            onPress={() => navigation.navigate('ConnectShop')}
          >
            <Feather name="plus" size={18} color={Colors.primary} />
          </TouchableOpacity>
        </View>

        {/* Active Shop Chips */}
        {shops.length > 0 && (
          <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.shopChips}>
            {shops.map((shop) => (
              <TouchableOpacity key={shop.id} onPress={() => {}}>
                <ShopTag shop={shop} />
              </TouchableOpacity>
            ))}
          </ScrollView>
        )}

        {/* Summary */}
        <SummaryCard title="Ringkasan Toko" stats={statItems} />

        {/* Quick Actions */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Aksi Cepat</Text>
          <View style={styles.actions}>
            <TouchableOpacity
              style={styles.actionCard}
              onPress={() => navigation.navigate('BulkStockUpdate')}
            >
              <View style={[styles.actionIcon, { backgroundColor: Colors.primaryLight }]}>
                <Feather name="layers" size={20} color={Colors.primary} />
              </View>
              <Text style={styles.actionLabel}>Update Stok Massal</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={styles.actionCard}
              onPress={() => navigation.navigate('BulkPriceUpdate')}
            >
              <View style={[styles.actionIcon, { backgroundColor: Colors.successLight }]}>
                <Feather name="tag" size={20} color={Colors.success} />
              </View>
              <Text style={styles.actionLabel}>Update Harga Massal</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={styles.actionCard}
              onPress={() => navigation.navigate('ConnectShop')}
            >
              <View style={[styles.actionIcon, { backgroundColor: Colors.infoLight }]}>
                <Feather name="link" size={20} color={Colors.info} />
              </View>
              <Text style={styles.actionLabel}>Hubungkan Toko</Text>
            </TouchableOpacity>
          </View>
        </View>

        {/* Recent Jobs */}
        {recentJobs.length > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Aktivitas Terakhir</Text>
            <View style={styles.jobs}>
              {recentJobs.map((job) => (
                <JobStatusCard key={job.jobId} job={job} />
              ))}
            </View>
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
