import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { shopsApi } from '@/api/shops';
import { useShopStore } from '@/stores/shopStore';
import { QUERY_KEYS } from '@/constants/queryKeys';
import type { Shop } from '@/types';

export function useShops() {
  const { setShops } = useShopStore();

  return useQuery<Shop[]>({
    queryKey: QUERY_KEYS.shops(),
    queryFn: async () => {
      const result = await shopsApi.list();
      setShops(result);
      return result;
    },
    staleTime: 60_000,
  });
}

export function useConnectShop() {
  const queryClient = useQueryClient();

  const getShopeeAuthUrl = useMutation({
    mutationFn: () => shopsApi.getShopeeAuthUrl(),
  });

  const getTikTokAuthUrl = useMutation({
    mutationFn: () => shopsApi.getTikTokAuthUrl(),
  });

  const disconnect = useMutation({
    mutationFn: (shopId: string) => shopsApi.disconnect(shopId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.shops() });
    },
  });

  const sync = useMutation({
    mutationFn: (shopId: string) => shopsApi.sync(shopId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.shops() });
      queryClient.invalidateQueries({ queryKey: ['products'] });
    },
  });

  return { getShopeeAuthUrl, getTikTokAuthUrl, disconnect, sync };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { productsApi } from '@/api/index';
import { useShopStore } from '@/stores/shopStore';
import { QUERY_KEYS } from '@/constants/queryKeys';
import type { ProductSummary } from '@/types';

interface ProductFilters {
  search?: string;
  status?: string;
}

export function useProducts(filters: ProductFilters = {}) {
  const { activeShopId } = useShopStore();

  return useQuery({
    queryKey: QUERY_KEYS.products(activeShopId ?? '', filters),
    queryFn: () =>
      productsApi.list({
        shopId: activeShopId!,
        search: filters.search,
        status: filters.status,
      }),
    enabled: !!activeShopId,
    staleTime: 30_000,
  });
}

export function useSyncProducts() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (shopId: string) => productsApi.list({ shopId }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['products'] });
    },
  });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { productsApi, inventoryApi, priceApi } from '@/api/index';
import { QUERY_KEYS } from '@/constants/queryKeys';
import type { ProductDetail } from '@/types';

export function useProductDetail(productId: string, shopId: string) {
  return useQuery<ProductDetail>({
    queryKey: QUERY_KEYS.productDetail(productId, shopId),
    queryFn: () => productsApi.detail(productId, shopId),
    staleTime: 20_000,
    enabled: !!productId && !!shopId,
  });
}

export function useUpdateStock(productId: string) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (input: { shopId: string; updates: Array<{ variantId: string; stock: number }> }) =>
      inventoryApi.updateStock(productId, input.shopId, input.updates),
    onSuccess: (_data, vars) => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.productDetail(productId, vars.shopId) });
      queryClient.invalidateQueries({ queryKey: ['products'] });
    },
  });
}

export function useUpdatePrice(productId: string) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (input: {
      shopId: string;
      updates: Array<{ variantId: string; price: number; originalPrice?: number }>;
    }) => priceApi.updatePrice(productId, input.shopId, input.updates),
    onSuccess: (_data, vars) => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.productDetail(productId, vars.shopId) });
      queryClient.invalidateQueries({ queryKey: ['products'] });
    },
  });
}

import { useState, useEffect } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { bulkApi } from '@/api/index';
import { QUERY_KEYS } from '@/constants/queryKeys';
import type { BulkStockItem, BulkPriceItem, BulkJobSummary } from '@/types';

export function useBulkJob() {
  const queryClient = useQueryClient();

  const createStockJob = useMutation({
    mutationFn: ({ shopId, items }: { shopId: string; items: BulkStockItem[] }) =>
      bulkApi.createStockJob(shopId, items),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['bulk-history'] });
    },
  });

  const createPriceJob = useMutation({
    mutationFn: ({ shopId, items }: { shopId: string; items: BulkPriceItem[] }) =>
      bulkApi.createPriceJob(shopId, items),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['bulk-history'] });
    },
  });

  return { createStockJob, createPriceJob };
}

export function useBulkJobStatus(jobId: string | null) {
  const [pollingInterval, setPollingInterval] = useState<number | false>(2000);

  const DONE = ['COMPLETED', 'FAILED', 'PARTIAL'];

  const query = useQuery({
    queryKey: QUERY_KEYS.bulkJobStatus(jobId ?? ''),
    queryFn: () => bulkApi.getStatus(jobId!),
    refetchInterval: pollingInterval,
    enabled: !!jobId,
    staleTime: 0,
  });

  useEffect(() => {
    const status = query.data?.status as string | undefined;
    if (status && DONE.includes(status)) {
      setPollingInterval(false);
    } else {
      setPollingInterval(2000);
    }
  }, [query.data?.status]);

  return query;
}

export function useBulkHistory(shopId?: string) {
  return useQuery<BulkJobSummary[]>({
    queryKey: QUERY_KEYS.bulkHistory(shopId),
    queryFn: () => bulkApi.getHistory(shopId),
    staleTime: 15_000,
  });
}

import { useEffect, useRef, useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { useAuthStore } from '@/stores/authStore';
import { getAccessToken } from '@/api/client';
import { API_URL } from '@/constants';

type EventHandler = (data: Record<string, unknown>) => void;

export function useRealtimeEvents(handlers?: Partial<Record<string, EventHandler>>) {
  const queryClient = useQueryClient();
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated);
  const stableHandlers = useRef(handlers);
  stableHandlers.current = handlers;

  const defaultHandler = useCallback(
    (type: string, data: Record<string, unknown>) => {
      if (type === 'shopee_webhook' || type === 'tiktok_webhook') {
        queryClient.invalidateQueries({ queryKey: ['products'] });
      }
      if (type === 'bulk_job_completed') {
        queryClient.invalidateQueries({ queryKey: ['bulk-history'] });
        queryClient.invalidateQueries({ queryKey: ['products'] });
      }
      stableHandlers.current?.[type]?.(data);
    },
    [queryClient],
  );

  useEffect(() => {
    if (!isAuthenticated) return;

    const token = getAccessToken();
    if (!token) return;

    const url = `${API_URL}/api/events/stream?token=${token}`;

    let es: EventSource;
    try {
      es = new EventSource(url);

      es.onmessage = (e) => {
        try {
          const data = JSON.parse(e.data as string) as Record<string, unknown>;
          defaultHandler(String(data.type ?? 'message'), data);
        } catch { /* empty */ }
      };

      const eventTypes = ['shopee_webhook', 'tiktok_webhook', 'bulk_job_started', 'bulk_job_progress', 'bulk_job_completed'];
      eventTypes.forEach((type) => {
        es.addEventListener(type, (e: Event) => {
          const me = e as MessageEvent;
          try {
            const data = JSON.parse(me.data as string) as Record<string, unknown>;
            defaultHandler(type, data);
          } catch { /* empty */ }
        });
      });
    } catch {
      return;
    }

    return () => {
      es?.close();
    };
  }, [isAuthenticated, defaultHandler]);
}

