import React from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { VariantRow } from '@/components/molecules/VariantRow';
import { Colors } from '@/constants';

export interface VariantItem {
  variantId: string;
  variantName: string;
  stock: number;
  price: number;
  originalPrice?: number;
  currency?: string;
  sku?: string;
  attributes?: Record<string, string>;
}

interface VariantTableProps {
  variants: VariantItem[];
  currency?: string;
  onVariantPress?: (variant: VariantItem) => void;
}

export function VariantTable({ variants, currency, onVariantPress }: VariantTableProps) {
  const totalStock = variants.reduce((sum, v) => sum + v.stock, 0);

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Varian ({variants.length})</Text>
        <Text style={styles.totalStock}>Total Stok: {totalStock}</Text>
      </View>

      {variants.map((v) => (
        <VariantRow
          key={v.variantId}
          name={v.variantName}
          stock={v.stock}
          price={v.price}
          currency={currency ?? v.currency}
          onPress={onVariantPress ? () => onVariantPress(v) : undefined}
        />
      ))}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    backgroundColor: Colors.cardBg,
    borderRadius: 12,
    overflow: 'hidden',
    borderWidth: 1,
    borderColor: Colors.border,
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingHorizontal: 16,
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: Colors.border,
  },
  headerTitle: { fontSize: 14, fontWeight: '700', color: Colors.heading },
  totalStock: { fontSize: 13, color: Colors.textSecondary },
});

import React, { useCallback } from 'react';
import { View, StyleSheet, RefreshControl } from 'react-native';
import { FlashList } from '@shopify/flash-list';
import { ProductCard } from '@/components/molecules/ProductCard';
import { Skeleton } from '@/components/atoms/Skeleton';
import { EmptyState } from '@/components/molecules/EmptyState';
import { Colors } from '@/constants';
import type { ProductSummary, Platform } from '@/types';

interface ProductListProps {
  products: ProductSummary[];
  platform?: Platform;
  isLoading: boolean;
  isRefreshing: boolean;
  onRefresh: () => void;
  onEndReached?: () => void;
  onProductPress: (product: ProductSummary) => void;
  onProductLongPress?: (product: ProductSummary) => void;
  isSelectMode?: boolean;
  isSelected?: (id: string) => boolean;
  ListHeaderComponent?: React.ReactElement;
}

function SkeletonCard() {
  return (
    <View style={styles.skeletonCard}>
      <Skeleton width={64} height={64} borderRadius={10} />
      <View style={styles.skeletonLines}>
        <Skeleton width="70%" height={14} />
        <Skeleton width="40%" height={12} />
        <View style={styles.skeletonRow}>
          <Skeleton width={60} height={20} borderRadius={9999} />
          <Skeleton width={60} height={20} borderRadius={9999} />
        </View>
      </View>
    </View>
  );
}

export function ProductList({
  products,
  platform = 'SHOPEE',
  isLoading,
  isRefreshing,
  onRefresh,
  onEndReached,
  onProductPress,
  onProductLongPress,
  isSelectMode,
  isSelected,
  ListHeaderComponent,
}: ProductListProps) {
  const renderItem = useCallback(
    ({ item }: { item: ProductSummary }) => (
      <ProductCard
        product={item}
        platform={platform}
        isSelectMode={isSelectMode}
        isSelected={isSelected ? isSelected(item.id) : false}
        onPress={() => onProductPress(item)}
        onLongPress={onProductLongPress ? () => onProductLongPress(item) : undefined}
      />
    ),
    [onProductPress, onProductLongPress, isSelectMode, isSelected, platform],
  );

  const keyExtractor = useCallback((item: ProductSummary) => item.platformProductId, []);

  if (isLoading) {
    return (
      <View style={styles.skeletonContainer}>
        {Array.from({ length: 6 }).map((_, i) => (
          <SkeletonCard key={i} />
        ))}
      </View>
    );
  }

  return (
    <FlashList
      data={products}
      renderItem={renderItem}
      keyExtractor={keyExtractor}
      estimatedItemSize={88}
      onEndReached={onEndReached}
      onEndReachedThreshold={0.3}
      contentContainerStyle={styles.list}
      ListHeaderComponent={ListHeaderComponent}
      ListEmptyComponent={
        <EmptyState
          icon="package"
          title="Belum Ada Produk"
          subtitle="Sambungkan toko dan sinkronkan produk untuk memulai."
        />
      }
      refreshControl={
        <RefreshControl
          refreshing={isRefreshing}
          onRefresh={onRefresh}
          tintColor={Colors.primary}
        />
      }
    />
  );
}

const styles = StyleSheet.create({
  list: { paddingBottom: 32 },
  skeletonContainer: { padding: 16, gap: 12 },
  skeletonCard: {
    flexDirection: 'row',
    gap: 12,
    padding: 12,
    backgroundColor: Colors.cardBg,
    borderRadius: 12,
  },
  skeletonLines: { flex: 1, gap: 8, justifyContent: 'center' },
  skeletonRow: { flexDirection: 'row', gap: 8 },
});

import { apiClient } from './client';
import { getAccessToken } from './client';
import { API_URL } from '@/constants';

export interface UploadedImage {
  imageId: string;
  imageUrl: string;
  width: number;
  height: number;
}

export const imageApi = {
  async uploadImage(shopId: string, uri: string, mimeType: string): Promise<UploadedImage> {
    const token = getAccessToken();

    const formData = new FormData();
    const filename = uri.split('/').pop() ?? 'image.jpg';
    formData.append('file', { uri, name: filename, type: mimeType } as unknown as Blob);
    formData.append('shopId', shopId);

    const response = await fetch(`${API_URL}/api/images/upload`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${token ?? ''}` },
      body: formData,
    });

    if (!response.ok) {
      const err = (await response.json()) as { error?: { message: string } };
      throw new Error(err.error?.message ?? 'Upload failed');
    }

    const json = (await response.json()) as { data: UploadedImage };
    return json.data;
  },

  async updateProductImages(
    productId: string,
    input: { shopId: string; images: Array<{ imageId: string; order: number }> },
  ): Promise<{ message: string }> {
    const { data } = await apiClient.patch<{ success: boolean; data: { message: string } }>(
      `/api/products/${productId}/images`,
      input,
    );
    return data.data;
  },
};

import React, { useCallback } from 'react';
import {
  View, Text, ScrollView, TouchableOpacity, StyleSheet,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useNavigation, useRoute } from '@react-navigation/native';
import type { NativeStackNavigationProp, RouteProp } from '@react-navigation/native-stack';
import { useQuery } from '@tanstack/react-query';
import { Image } from 'expo-image';
import { Feather } from '@expo/vector-icons';
import { VariantTable } from '@/components/organisms/VariantTable';
import type { VariantItem } from '@/components/organisms/VariantTable';
import { PlatformTag } from '@/components/atoms/PlatformTag';
import { Badge } from '@/components/atoms/Badge';
import { Skeleton } from '@/components/atoms/Skeleton';
import { ErrorState } from '@/components/molecules/ErrorState';
import { Colors } from '@/constants';
import { QUERY_KEYS } from '@/constants/queryKeys';
import { productsApi } from '@/api/index';
import type { RootStackParamList, ProductDetail } from '@/types';
import { formatCurrency } from '@/utils/format';

type Nav = NativeStackNavigationProp<RootStackParamList>;
type Route = RouteProp<RootStackParamList, 'ProductDetail'>;

const STATUS_MAP: Record<string, { label: string; variant: 'success' | 'danger' | 'neutral' }> = {
  ACTIVE: { label: 'Aktif', variant: 'success' },
  SOLD_OUT: { label: 'Habis', variant: 'danger' },
  INACTIVE: { label: 'Non-aktif', variant: 'neutral' },
};

export function ProductDetailScreen() {
  const navigation = useNavigation<Nav>();
  const route = useRoute<Route>();
  const { productId, shopId } = route.params;

  const { data: product, isLoading, error, refetch } = useQuery<ProductDetail>({
    queryKey: QUERY_KEYS.productDetail(productId, shopId),
    queryFn: () => productsApi.detail(productId, shopId),
    staleTime: 20_000,
  });

  const handleVariantPress = useCallback(
    (_variant: VariantItem) => {
      navigation.navigate('EditStock', { productId, shopId });
    },
    [navigation, productId, shopId],
  );

  if (isLoading) {
    return (
      <SafeAreaView style={styles.safe}>
        <ScrollView contentContainerStyle={styles.content}>
          <Skeleton width="100%" height={240} borderRadius={0} />
          <View style={{ padding: 16, gap: 12 }}>
            <Skeleton width="80%" height={20} />
            <Skeleton width="50%" height={14} />
            <Skeleton width="100%" height={120} />
          </View>
        </ScrollView>
      </SafeAreaView>
    );
  }

  if (error || !product) {
    return (
      <SafeAreaView style={styles.safe}>
        <ErrorState message="Gagal memuat detail produk." onRetry={refetch} />
      </SafeAreaView>
    );
  }

  const statusInfo = STATUS_MAP[product.status] ?? { label: product.status, variant: 'neutral' as const };
  const coverImage = product.images?.[0]?.url ?? product.coverImage;

  const variantItems: VariantItem[] = (product.variants ?? []).map((v) => ({
    variantId: v.variantId,
    variantName: v.name,
    stock: v.stock,
    price: v.price,
    originalPrice: v.originalPrice,
    currency: v.currency,
    sku: v.sku,
    attributes: v.attributes,
  }));

  return (
    <SafeAreaView style={styles.safe} edges={['bottom']}>
      <ScrollView contentContainerStyle={styles.content}>
        <Image source={{ uri: coverImage }} style={styles.cover} contentFit="cover" />

        <View style={styles.infoSection}>
          <View style={styles.tagRow}>
            <PlatformTag platform="SHOPEE" />
            <Badge label={statusInfo.label} variant={statusInfo.variant} />
          </View>
          <Text style={styles.productName}>{product.name}</Text>
          <Text style={styles.priceRange}>
            {formatCurrency(product.priceRange.min, product.priceRange.currency)}
            {product.priceRange.min !== product.priceRange.max &&
              ` – ${formatCurrency(product.priceRange.max, product.priceRange.currency)}`}
          </Text>
        </View>

        <View style={styles.section}>
          <VariantTable
            variants={variantItems}
            currency={product.priceRange.currency}
            onVariantPress={handleVariantPress}
          />
        </View>

        {(product.images?.length ?? 0) > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Gambar Produk ({product.images.length})</Text>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.imageRow}>
              {product.images.map((img) => (
                <Image
                  key={img.imageId}
                  source={{ uri: img.url }}
                  style={styles.thumbImage}
                  contentFit="cover"
                />
              ))}
            </ScrollView>
          </View>
        )}
      </ScrollView>

      <View style={styles.actionBar}>
        <TouchableOpacity
          style={[styles.actionBtn, styles.actionBtnPrimary]}
          onPress={() => navigation.navigate('EditStock', { productId, shopId })}
        >
          <Feather name="layers" size={16} color={Colors.white} />
          <Text style={styles.actionBtnPrimaryLabel}>Edit Stok</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={[styles.actionBtn, styles.actionBtnSecondary]}
          onPress={() => navigation.navigate('EditPrice', { productId, shopId })}
        >
          <Feather name="tag" size={16} color={Colors.primary} />
          <Text style={styles.actionBtnSecondaryLabel}>Edit Harga</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={[styles.actionBtn, styles.actionBtnSecondary]}
          onPress={() => navigation.navigate('EditImage', { productId, shopId })}
        >
          <Feather name="image" size={16} color={Colors.primary} />
          <Text style={styles.actionBtnSecondaryLabel}>Edit Gambar</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

